/* ===== vanaf-prijzen op dienstkaarten (uit echte staffels) ===== */
function minFrom(id){
  /* laagste haalbare prijs over alle combinaties (zelfde wiskunde als priceFor) */
  const P=PRICES[id];if(!P)return null;
  if(P.matrix){
    const M=P.matrix;let mh=null;
    const scan=a=>a.forEach(v=>{if(v!=null&&(mh===null||v<mh))mh=v;});
    M.papers.forEach(scan);scan(M.p1);scan(M.p4);
    if(mh===null)return null;
    return Math.round(mh*Math.min(...M.col)*1.30*1.21*100)/100;
  }
  let best=null;
  const upd=v=>{if(v!=null&&(best===null||v<best))best=v;};
  if(P.override)for(const gi in P.override)for(const oi in P.override[gi]){
    const o=P.override[gi][oi];
    if(o&&o.t)o.t.forEach(v=>upd(v));
  }
  let m=1;
  if(P.mul)for(const gi in P.mul){
    let mm=null;
    P.mul[gi].forEach(v=>{if(v!=null&&(mm===null||v<mm))mm=v;});
    if(mm!=null)m*=mm;
  }
  P.tiers.forEach(t=>{if(t!=null)upd(t*m);});
  return best!=null?Math.ceil(best*2)/2:null;
}
function fillFrom(){
  document.querySelectorAll('[data-from]').forEach(el=>{
    const v=minFrom(el.getAttribute('data-from'));
    el.textContent=v!=null?T[lang].pr_from+' \u20ac '+v.toFixed(2):T[lang].cart_onreq;
  });
}

