function sendQuote(e){
  e.preventDefault();
  const n=document.getElementById('f-name').value,
        em=document.getElementById('f-email').value,
        s=document.getElementById('f-service').value,
        m=document.getElementById('f-msg').value,
        ph=(document.getElementById('f-phone')||{value:''}).value,
        dl=(document.getElementById('f-dead')||{value:''}).value;
  const SUBJ={nl:'Offerte-aanvraag: ',fr:'Demande de devis : ',en:'Quote request: ',de:'Angebotsanfrage: '};const subj=encodeURIComponent(SUBJ[lang]+s);
  const NM={nl:'Naam: ',fr:'Nom : ',en:'Name: ',de:'Name: '};const TL={nl:'Telefoon: ',fr:'Téléphone : ',en:'Phone: ',de:'Telefon: '};const DL={nl:'Deadline: ',fr:'Échéance : ',en:'Deadline: ',de:'Termin: '};const body=encodeURIComponent(NM[lang]+n+'\nE-mail: '+em+(ph?'\n'+TL[lang]+ph:'')+(dl?'\n'+DL[lang]+dl:'')+'\n\n'+m);
  const FL={nl:'Bestanden: ',fr:'Fichiers : ',en:'Files: ',de:'Dateien: '};
  let fileLine='';
  if(window.pbFormFiles&&window.pbFormFiles().length)fileLine='\n'+FL[lang]+window.pbFormFiles().join(', ');
  const body2=encodeURIComponent(decodeURIComponent(body)+fileLine);
  try{
    const L=JSON.parse(localStorage.getItem('pb_myreq')||'[]');
    L.unshift({ts:Date.now(),s:s,m:(m||'').slice(0,400)});
    localStorage.setItem('pb_myreq',JSON.stringify(L.slice(0,20)));
  }catch(err){}
  window.location.href='mailto:info@prismabel.com?subject='+subj+'&body='+body2;
  return false;
}

